class Solution {
    public int maxScoreSightseeingPair(int[] values) {
        int maxScore = 0;
        int left = values[0] + 0;
        for (int j = 1; j < values.length; j++) {
            maxScore = Math.max(maxScore, left + values[j] - j);
            left = Math.max(left, values[j] + j);
        }
        return maxScore;
    }
}
